import json
import os
from datetime import datetime

def main():
    python_ok = False
    search_ok = False
    file_ok = False

    # Check Python output
    try:
        with open('python_check.txt', 'r') as f:
            content = f.read().strip()
            if content == '4':
                python_ok = True
    except FileNotFoundError:
        pass

    # Check search result
    try:
        with open('search_result.txt', 'r') as f:
            content = f.read().strip()
            if content:
                search_ok = True
    except FileNotFoundError:
        pass

    # Check hello.txt
    try:
        with open('hello.txt', 'r') as f:
            content = f.read().strip()
            if content == 'AI Partner is healthy':
                file_ok = True
    except FileNotFoundError:
        pass

    # Write final health check
    data = {
        "python_ok": python_ok,
        "search_ok": search_ok,
        "file_ok": file_ok,
        "timestamp": datetime.utcnow().isoformat() + 'Z'
    }

    with open('health-check.json', 'w') as f:
        json.dump(data, f, indent=2)

if __name__ == '__main__':
    main()
